/**
 * FORGE Browser Test Template — Puppeteer/Playwright scaffold
 *
 * Auto-generated by FORGE for spec-level UI validation.
 * Each test step captures a screenshot with annotations.
 *
 * Usage:
 *   FORGE_SPEC=NNN FORGE_EVIDENCE_DIR=path node browser-test-template.js
 *
 * Environment:
 *   FORGE_SPEC          — spec number (e.g., "042")
 *   FORGE_EVIDENCE_DIR  — path to store screenshots/video
 *   FORGE_BASE_URL      — application base URL (default: http://localhost:3000)
 *   FORGE_HEADLESS       — "true" (default) or "false" for headed mode
 *   FORGE_VIDEO          — "true" (default) or "false" to disable video recording
 *   FORGE_BROWSER        — "chromium" (default), "firefox", or "webkit" (Playwright only)
 *   FORGE_RUNNER         — "puppeteer" or "playwright" (auto-detected from installed packages)
 */

const fs = require("fs");
const path = require("path");

// --- Configuration ---
const SPEC = process.env.FORGE_SPEC || "000";
const EVIDENCE_DIR =
  process.env.FORGE_EVIDENCE_DIR ||
  path.join("tmp", "evidence", `SPEC-${SPEC}-browser`);
const BASE_URL = process.env.FORGE_BASE_URL || "http://localhost:3000";
const HEADLESS = process.env.FORGE_HEADLESS !== "false";
const RECORD_VIDEO = process.env.FORGE_VIDEO !== "false";
const BROWSER_TYPE = process.env.FORGE_BROWSER || "chromium";

// --- Evidence state ---
const evidence = {
  spec: SPEC,
  startTime: null,
  endTime: null,
  steps: [],
  summary: { total: 0, passed: 0, failed: 0, warnings: 0 },
  videoPath: null,
};

// --- Detect runner ---
function detectRunner() {
  const explicit = process.env.FORGE_RUNNER;
  if (explicit) return explicit;
  try {
    require.resolve("playwright");
    return "playwright";
  } catch {
    try {
      require.resolve("puppeteer");
      return "puppeteer";
    } catch {
      console.error(
        "FORGE: Neither Playwright nor Puppeteer found. Install one:\n" +
          "  npm install --save-dev playwright\n" +
          "  npm install --save-dev puppeteer"
      );
      process.exit(1);
    }
  }
}

// --- Screenshot helper ---
async function captureStep(page, stepIndex, description, expected, runner) {
  const filename = `step-${String(stepIndex).padStart(3, "0")}.png`;
  const filepath = path.join(EVIDENCE_DIR, filename);

  if (runner === "playwright") {
    await page.screenshot({ path: filepath, fullPage: true });
  } else {
    await page.screenshot({ path: filepath, fullPage: true });
  }

  const step = {
    index: stepIndex,
    timestamp: new Date().toISOString(),
    description: description,
    expected: expected,
    screenshotPath: filepath,
    assessment: null, // filled by assessStep
  };

  evidence.steps.push(step);
  return step;
}

// --- Assessment helper ---
function assessStep(stepIndex, actual, passed, notes) {
  const step = evidence.steps.find((s) => s.index === stepIndex);
  if (!step) return;

  step.assessment = {
    actual: actual,
    passed: passed,
    notes: notes || "",
  };

  evidence.summary.total++;
  if (passed) {
    evidence.summary.passed++;
  } else {
    evidence.summary.failed++;
  }
}

// --- Write evidence manifest ---
function writeManifest() {
  evidence.endTime = new Date().toISOString();

  const manifestPath = path.join(EVIDENCE_DIR, "manifest.json");
  fs.writeFileSync(manifestPath, JSON.stringify(evidence, null, 2));

  // Write human-readable summary
  const summaryPath = path.join(EVIDENCE_DIR, "summary.md");
  let md = `# Browser Test Evidence — Spec ${SPEC}\n\n`;
  md += `- Start: ${evidence.startTime}\n`;
  md += `- End: ${evidence.endTime}\n`;
  md += `- Results: ${evidence.summary.passed}/${evidence.summary.total} passed`;
  if (evidence.summary.failed > 0)
    md += ` (${evidence.summary.failed} failed)`;
  md += "\n";
  if (evidence.videoPath) md += `- Video: ${evidence.videoPath}\n`;
  md += "\n## Steps\n\n";

  for (const step of evidence.steps) {
    const status = step.assessment
      ? step.assessment.passed
        ? "PASS"
        : "FAIL"
      : "PENDING";
    md += `### Step ${step.index} — ${step.description}\n`;
    md += `- Expected: ${step.expected}\n`;
    if (step.assessment) {
      md += `- Actual: ${step.assessment.actual}\n`;
      md += `- Status: **${status}**\n`;
      if (step.assessment.notes) md += `- Notes: ${step.assessment.notes}\n`;
    }
    md += `- Screenshot: [${path.basename(step.screenshotPath)}](${step.screenshotPath})\n\n`;
  }

  fs.writeFileSync(summaryPath, md);
  return { manifestPath, summaryPath };
}

// --- Main runner ---
async function runBrowserTest(testFn) {
  const runnerName = detectRunner();

  // Ensure evidence directory exists
  fs.mkdirSync(EVIDENCE_DIR, { recursive: true });

  evidence.startTime = new Date().toISOString();

  let browser, page, context;

  if (runnerName === "playwright") {
    const playwright = require("playwright");
    const browserType = playwright[BROWSER_TYPE];

    browser = await browserType.launch({ headless: HEADLESS });
    const contextOpts = {};
    if (RECORD_VIDEO) {
      contextOpts.recordVideo = {
        dir: path.join(EVIDENCE_DIR, "video"),
        size: { width: 1280, height: 720 },
      };
    }
    context = await browser.newContext(contextOpts);
    page = await context.newPage();
  } else {
    const puppeteer = require("puppeteer");
    browser = await puppeteer.launch({
      headless: HEADLESS ? "new" : false,
      args: ["--no-sandbox", "--disable-setuid-sandbox"],
    });
    page = await browser.newPage();
    await page.setViewport({ width: 1280, height: 720 });

    if (RECORD_VIDEO) {
      // Puppeteer video requires puppeteer-screen-recorder
      try {
        const { PuppeteerScreenRecorder } = require("puppeteer-screen-recorder");
        const recorder = new PuppeteerScreenRecorder(page, {
          fps: 15,
          ffmpeg_Path: null, // use system ffmpeg
        });
        const videoPath = path.join(EVIDENCE_DIR, "recording.mp4");
        await recorder.start(videoPath);
        evidence.videoPath = videoPath;
        evidence._recorder = recorder;
      } catch {
        console.warn(
          "FORGE: puppeteer-screen-recorder not found — video recording disabled.\n" +
            "  Install: npm install --save-dev puppeteer-screen-recorder"
        );
      }
    }
  }

  const helpers = {
    page,
    browser,
    context,
    baseUrl: BASE_URL,
    runner: runnerName,
    capture: (stepIndex, description, expected) =>
      captureStep(page, stepIndex, description, expected, runnerName),
    assess: assessStep,
  };

  try {
    await testFn(helpers);
  } catch (err) {
    // Capture error screenshot
    const errorPath = path.join(EVIDENCE_DIR, "error-screenshot.png");
    try {
      await page.screenshot({ path: errorPath, fullPage: true });
    } catch {
      /* page may be closed */
    }

    evidence.steps.push({
      index: evidence.steps.length + 1,
      timestamp: new Date().toISOString(),
      description: "UNHANDLED ERROR",
      expected: "No errors",
      screenshotPath: errorPath,
      assessment: {
        actual: err.message,
        passed: false,
        notes: `Error: ${err.stack}`,
      },
    });
    evidence.summary.total++;
    evidence.summary.failed++;
  } finally {
    // Stop video recording
    if (runnerName === "puppeteer" && evidence._recorder) {
      await evidence._recorder.stop();
      delete evidence._recorder;
    }
    if (runnerName === "playwright" && context) {
      const videoPage = context.pages()[0];
      if (videoPage) {
        const video = videoPage.video();
        if (video) {
          try {
            const videoPath = await video.path();
            evidence.videoPath = videoPath;
          } catch {
            /* video may not exist */
          }
        }
      }
      await context.close();
    }
    if (browser) await browser.close();
  }

  const result = writeManifest();

  // Print results
  console.log("\n--- FORGE Browser Test Results ---");
  console.log(`Spec: ${SPEC}`);
  console.log(
    `Results: ${evidence.summary.passed}/${evidence.summary.total} passed`
  );
  if (evidence.summary.failed > 0)
    console.log(`Failed: ${evidence.summary.failed}`);
  console.log(`Evidence: ${EVIDENCE_DIR}`);
  console.log(`Manifest: ${result.manifestPath}`);
  console.log(`Summary: ${result.summaryPath}`);
  if (evidence.videoPath) console.log(`Video: ${evidence.videoPath}`);
  console.log("----------------------------------\n");

  return evidence;
}

// --- Exports ---
module.exports = {
  runBrowserTest,
  captureStep,
  assessStep,
  writeManifest,
  evidence,
  // Constants for consumer test scripts
  SPEC,
  EVIDENCE_DIR,
  BASE_URL,
  HEADLESS,
};
